 * Configuration options for TemplateEngine
 */
export interface TemplateEngineOptions {
  /**
   * Directory containing template files
   */
  templateDir: string;

  /**
   * Maximum number of compiled templates to cache
   * @default 100
   */
  cacheSize?: number;

  /**
   * Whether to throw errors for missing variables in strict mode
   * @default false
   */
  strict?: boolean;

  /**
   * Disable HTML escaping (use only for trusted content)
   * @default false
   */
  noEscape?: boolean;
}

