 * const engine = new TemplateEngine({ templateDir: './templates' });
 *
 * // Compile inline template
 * const html = engine.compile('Hello, {{name}}!', { name: 'World' });
 *
 * // Render from file
 * const digest = await engine.renderFromFile('digest.hbs', { emails: [...] });
 *
 * // Register partial
 * engine.registerPartial('email-summary', '<div>{{subject}}</div>');
 * ```
