   * Compile and render an inline template string
   *
   * @param templateString - Handlebars template string
   * @param data - Template data context
   * @returns Rendered HTML string
   * @throws Error if template syntax is invalid
   *
   * @example
   * ```typescript
   * const html = engine.compile('Hello, {{name}}!', { name: 'World' });
   * // => "Hello, World!"
   * ```
   */
  public compile(templateString: string, data: Record<string, unknown>): string {
    try {
      // Check cache first
      let template = this.templateCache.get(templateString);

      if (template) {
        this.cacheHits++;
      } else {
        this.cacheMisses++;

        // Compile template
        template = Handlebars.compile(templateString, {
          strict: this.strict,
          noEscape: this.noEscape,
        });

        // Cache with size limit (LRU-like eviction)
        if (this.templateCache.size >= this.cacheSize) {
          const firstKey = this.templateCache.keys().next().value;
          this.templateCache.delete(firstKey);
        }

        this.templateCache.set(templateString, template);
      }

      // Render template with data
      return template(data);
    } catch (error) {
      if (error instanceof Error) {
        throw new Error(`Template compilation error: ${error.message}`);
      }
      throw error;
    }
