   * Get cache statistics for performance monitoring
   *
   * @returns Cache statistics including size, hits, and misses
   */
  public getCacheStats(): CacheStats {
    return {
      size: this.templateCache.size,
      hits: this.cacheHits,
      misses: this.cacheMisses,
    };
  }

  /**
   * Get configured template directory
   *
   * @returns Template directory path
   */
  public getTemplateDir(): string {
    return this.templateDir;
  }

  /**
   * Register all default Handlebars helpers
   * @private
   */
  private registerDefaultHelpers(): void {
    // Date formatting helper
    Handlebars.registerHelper('formatDate', function (date: Date, format?: string) {
      if (!(date instanceof Date)) {
        return '';
      }

      if (format === 'YYYY-MM-DD') {
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
      }

      // Default format: MM/DD/YYYY
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const year = date.getFullYear();
      return `${month}/${day}/${year}`;
    });

    // Text truncation helper with ellipsis
    Handlebars.registerHelper('truncate', function (text: string, length: number) {
      if (typeof text !== 'string') {
        return '';
      }

      if (text.length <= length) {
        return text;
      }

      return text.substring(0, length) + '...';
    });

    // Pluralization helper
    Handlebars.registerHelper('pluralize', function (count: number, singular: string, plural?: string) {
      if (count === 1) {
        return singular;
      }

      return plural ?? `${singular}s`;
    });

    // Uppercase helper
    Handlebars.registerHelper('upper', function (text: string) {
      return typeof text === 'string' ? text.toUpperCase() : '';
    });

    // Lowercase helper
    Handlebars.registerHelper('lower', function (text: string) {
      return typeof text === 'string' ? text.toLowerCase() : '';
    });

    // Capitalize first letter helper
    Handlebars.registerHelper('capitalize', function (text: string) {
      if (typeof text !== 'string' || text.length === 0) {
        return '';
      }

      return text.charAt(0).toUpperCase() + text.slice(1);
    });

    // Equality check helper
    Handlebars.registerHelper('eq', function (a: any, b: any) {
      return a === b;
    });

    // Greater than helper
    Handlebars.registerHelper('gt', function (a: number, b: number) {
      return a > b;
    });

    // Less than helper
    Handlebars.registerHelper('lt', function (a: number, b: number) {
      return a < b;
    });

    // Extract email address from full address string
    Handlebars.registerHelper('extractEmail', function (address: string) {
      if (typeof address !== 'string') {
        return '';
      }

      const match = address.match(/<(.+?)>/);
      return match ? match[1] : address;
    });

    // Extract name from full address string
    Handlebars.registerHelper('extractName', function (address: string) {
      if (typeof address !== 'string') {
        return '';
      }

      const match = address.match(/^(.+?)\s*</);
      return match ? match[1].trim() : address;
    });

    // Email snippet helper (truncate at word boundary)
    Handlebars.registerHelper('emailSnippet', function (body: string, length: number) {
      if (typeof body !== 'string') {
        return '';
      }

      if (body.length <= length) {
        return body;
      }

      // Find last space before length limit
      const truncated = body.substring(0, length);
      const lastSpace = truncated.lastIndexOf(' ');

      if (lastSpace > 0) {
        return truncated.substring(0, lastSpace) + '...';
      }

      return truncated + '...';
    });

    // Urgency level CSS class helper
    Handlebars.registerHelper('urgencyClass', function (urgency: string) {
      if (typeof urgency !== 'string') {
        return 'urgency-low';
      }

      return `urgency-${urgency.toLowerCase()}`;
    });

    // Category CSS class helper
    Handlebars.registerHelper('categoryClass', function (category: string) {
      if (typeof category !== 'string') {
        return 'category-unknown';
      }

      return `category-${category.toLowerCase().replace(/\s+/g, '-')}`;
    });
  }
}

