### 6. Missing Template Size Limits

**Issue:** No limits on template string size or file size. Large templates could cause memory exhaustion.

**Recommendation:**
```typescript
export interface TemplateEngineOptions {
  templateDir: string;
  cacheSize?: number;
  strict?: boolean;
  noEscape?: boolean;
  maxTemplateSize?: number;  // <-- ADD THIS (default: 1MB)
}

public async renderFromFile(templateName: string, data: Record<string, unknown>): Promise<string> {
  const templatePath = path.join(this.templateDir, templateName);
  this.validateTemplatePath(templatePath);

  const stats = await fs.stat(templatePath);
  if (stats.size > this.maxTemplateSize) {
    throw new Error(`Template file too large: ${stats.size} bytes (max: ${this.maxTemplateSize})`);
  }

  const templateContent = await fs.readFile(templatePath, 'utf-8');
  // ...
}
```

