  constructor(options: TemplateEngineOptions) {
    this.templateDir = options.templateDir;
    this.cacheSize = options.cacheSize ?? 100;
    this.strict = options.strict ?? false;
    this.noEscape = options.noEscape ?? false;

    this.templateCache = new Map();

    // Register custom helpers on initialization
    this.registerDefaultHelpers();
  }

  /**
   * Compile and render an inline template string
   *
   * @param templateString - Handlebars template string
   * @param data - Template data context
   * @returns Rendered HTML string
   * @throws Error if template syntax is invalid
   *
   * @example
   * ```typescript
   * const html = engine.compile('Hello, {{name}}!', { name: 'World' });
   * // => "Hello, World!"
   * ```
   */
  public compile(templateString: string, data: Record<string, unknown>): string {
    try {
      // Check cache first
      let template = this.templateCache.get(templateString);

      if (template) {
        this.cacheHits++;
      } else {
        this.cacheMisses++;

        // Compile template
        template = Handlebars.compile(templateString, {
          strict: this.strict,
          noEscape: this.noEscape,
        });

        // Cache with size limit (FIFO eviction)
        if (this.templateCache.size >= this.cacheSize) {
          const firstKey = this.templateCache.keys().next().value;
          if (firstKey !== undefined) {
            this.templateCache.delete(firstKey);
          }
        }

        this.templateCache.set(templateString, template);
      }

      // Render template with data
      return template(data);
    } catch (error) {
      if (error instanceof Error) {
        throw new Error(`Template compilation error: ${error.message}`);
      }
      throw error;
    }
  }

  /**
   * Load and render a template from the file system
   *
   * @param templateName - Template file name (e.g., 'digest.hbs')
   * @param data - Template data context
   * @returns Rendered HTML string
   * @throws Error if template file not found or syntax invalid
   *
   * @example
   * ```typescript
   * const html = await engine.renderFromFile('digest.hbs', {
   *   categories: [...],
   *   totalEmails: 42
   * });
   * ```
   */
  public async renderFromFile(templateName: string, data: Record<string, unknown>): Promise<string> {
    const templatePath = path.join(this.templateDir, templateName);

    try {
      // Check cache first
      let template = this.templateCache.get(templatePath);

      if (template) {
        this.cacheHits++;
      } else {
        this.cacheMisses++;

        // Load template from file
        const templateContent = await fs.readFile(templatePath, 'utf-8');

        // Compile template
        template = Handlebars.compile(templateContent, {
          strict: this.strict,
          noEscape: this.noEscape,
        });

        // Cache compiled template
        if (this.templateCache.size >= this.cacheSize) {
          const firstKey = this.templateCache.keys().next().value;
          this.templateCache.delete(firstKey);
        }

        this.templateCache.set(templatePath, template);
      }

      // Render template with data
      return template(data);
    } catch (error: unknown) {
      if (error && typeof error === 'object' && 'code' in error && error.code === 'ENOENT') {
        const errno = 'errno' in error ? error.errno : 'unknown';
        throw new Error(`Template file not found: ${templatePath} (errno: ${errno})`);
      }
      if (error instanceof Error) {
        throw new Error(`Template rendering error: ${error.message}`);
      }
      throw error;
    }
  }

  /**
   * Register a Handlebars partial template
   *
   * @param name - Partial name (used as {{> name}})
   * @param template - Partial template string
   *
   * @example
   * ```typescript
   * engine.registerPartial('email-summary', '<div>{{subject}} - {{from}}</div>');
   *
   * // Use in template
   * const html = engine.compile('{{> email-summary}}', {
   *   subject: 'Hello',
   *   from: 'john@example.com'
   * });
   * ```
   */
  public registerPartial(name: string, template: string): void {
    Handlebars.registerPartial(name, template);
  }

  /**
   * Unregister a Handlebars partial template
   *
   * @param name - Partial name to unregister
   */
  public unregisterPartial(name: string): void {
    Handlebars.unregisterPartial(name);
  }

  /**
   * Load and register all partial templates from a directory
   *
   * @param partialsDir - Directory containing partial template files
   * @throws Error if directory cannot be read
   *
   * @example
   * ```typescript
   * await engine.loadPartials('./templates/partials');
   * // Loads all *.hbs files as partials with file name as partial name
   * ```
   */
  public async loadPartials(partialsDir: string): Promise<void> {
    try {
      const files = await fs.readdir(partialsDir);

      for (const file of files) {
        if (file.endsWith('.hbs') || file.endsWith('.handlebars')) {
          const filePath = path.join(partialsDir, file);
          const content = await fs.readFile(filePath, 'utf-8');
          const partialName = path.basename(file, path.extname(file));

          this.registerPartial(partialName, content);
        }
      }
    } catch (error: unknown) {
      if (error && typeof error === 'object' && 'code' in error && error.code === 'ENOENT') {
        const errno = 'errno' in error ? error.errno : 'unknown';
        throw new Error(`Partials directory not found: ${partialsDir} (errno: ${errno})`);
      }
      throw error;
    }
  }

  /**
   * Register a custom Handlebars helper function
   *
   * @param name - Helper name
   * @param helperFn - Helper function
   *
   * @example
   * ```typescript
   * engine.registerHelper('shout', (text: string) => text.toUpperCase());
   *
   * const html = engine.compile('{{shout message}}', { message: 'hello' });
   * // => "HELLO"
   * ```
   */
  public registerHelper(name: string, helperFn: Handlebars.HelperDelegate): void {
    Handlebars.registerHelper(name, helperFn);
  }

  /**
   * Pre-compile multiple templates for better performance
   *
   * @param templates - Map of template name to template string
   *
   * @example
   * ```typescript
   * await engine.precompileTemplates({
   *   greeting: 'Hello, {{name}}!',
   *   farewell: 'Goodbye, {{name}}!'
   * });
   * ```
   */
  public async precompileTemplates(templates: Record<string, string>): Promise<void> {
    for (const [, templateString] of Object.entries(templates)) {
      const template = Handlebars.compile(templateString, {
        strict: this.strict,
        noEscape: this.noEscape,
      });

      this.templateCache.set(templateString, template);
    }
  }

  /**
   * Clear all cached templates
   */
  public clearCache(): void {
    this.templateCache.clear();
    this.cacheHits = 0;
    this.cacheMisses = 0;
  }

  /**
   * Get current number of cached templates
   *
   * @returns Number of cached templates
   */
  public getCacheSize(): number {
    return this.templateCache.size;
  }

  /**
   * Get cache statistics for performance monitoring
   *
   * @returns Cache statistics including size, hits, and misses
   */
  public getCacheStats(): CacheStats {
    return {
      size: this.templateCache.size,
      hits: this.cacheHits,
      misses: this.cacheMisses,
    };
  }

  /**
   * Get configured template directory
   *
   * @returns Template directory path
   */
  public getTemplateDir(): string {
    return this.templateDir;
  }

  /**
   * Register all default Handlebars helpers
   * @private
   */
  private registerDefaultHelpers(): void {
    // Date formatting helper
    Handlebars.registerHelper('formatDate', function (date: Date, format?: string) {
      if (!(date instanceof Date)) {
        return '';
      }

      if (format === 'YYYY-MM-DD') {
        const year = date.getFullYear();
        const month = String(date.getMonth() + 1).padStart(2, '0');
        const day = String(date.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
      }

      // Default format: MM/DD/YYYY
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const year = date.getFullYear();
      return `${month}/${day}/${year}`;
    });

    // Text truncation helper with ellipsis
    Handlebars.registerHelper('truncate', function (text: string, length: number) {
      if (typeof text !== 'string') {
        return '';
      }

      if (text.length <= length) {
        return text;
      }

      return text.substring(0, length) + '...';
    });

    // Pluralization helper
    Handlebars.registerHelper('pluralize', function (count: number, singular: string, plural?: string) {
      if (count === 1) {
        return singular;
      }

      // Handle empty string as undefined (fallback to default pluralization)
      const pluralForm = plural && plural.length > 0 ? plural : `${singular}s`;
      return pluralForm;
    });

    // Uppercase helper
    Handlebars.registerHelper('upper', function (text: string) {
      return typeof text === 'string' ? text.toUpperCase() : '';
    });

    // Lowercase helper
    Handlebars.registerHelper('lower', function (text: string) {
      return typeof text === 'string' ? text.toLowerCase() : '';
    });

    // Capitalize first letter helper
    Handlebars.registerHelper('capitalize', function (text: string) {
      if (typeof text !== 'string' || text.length === 0) {
        return '';
      }

      return text.charAt(0).toUpperCase() + text.slice(1);
    });

    // Equality check helper
    Handlebars.registerHelper('eq', function (a: unknown, b: unknown) {
      return a === b;
    });

    // Greater than helper
    Handlebars.registerHelper('gt', function (a: number, b: number) {
      return a > b;
    });

    // Less than helper
    Handlebars.registerHelper('lt', function (a: number, b: number) {
      return a < b;
    });

    // Extract email address from full address string
    Handlebars.registerHelper('extractEmail', function (address: string) {
      if (typeof address !== 'string') {
        return '';
      }

      const match = address.match(/<(.+?)>/);
      return match ? match[1] : address;
    });

    // Extract name from full address string
    Handlebars.registerHelper('extractName', function (address: string) {
      if (typeof address !== 'string') {
        return '';
      }

      const match = address.match(/^(.+?)\s*</);
      return match ? match[1].trim() : address;
    });

    // Email snippet helper (truncate at word boundary)
    Handlebars.registerHelper('emailSnippet', function (body: string, length: number) {
      if (typeof body !== 'string') {
        return '';
      }

      if (body.length <= length) {
        return body;
      }

      // Find last space before length limit
      const truncated = body.substring(0, length);
      const lastSpace = truncated.lastIndexOf(' ');

      if (lastSpace > 0) {
        return truncated.substring(0, lastSpace) + '...';
      }

      return truncated + '...';
    });

    // Urgency level CSS class helper
    Handlebars.registerHelper('urgencyClass', function (urgency: string) {
      if (typeof urgency !== 'string') {
        return 'urgency-low';
      }

      return `urgency-${urgency.toLowerCase()}`;
    });

    // Category CSS class helper
    Handlebars.registerHelper('categoryClass', function (category: string) {
      if (typeof category !== 'string') {
        return 'category-unknown';
      }

      return `category-${category.toLowerCase().replace(/\s+/g, '-')}`;
    });
  }
}
